const Q_BIOLOGY_2003=[{"id": "objective>Biology>2003>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the egg of a bird, the embryo is located in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chalaza</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yolk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">albumen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">embryo disc</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the egg of a bird, the embryo is located in the embryo disc. The embryo disc, also known as the blastodisc, is the fertilized portion of the egg where the embryo begins to form. The chalaza anchors the yolk in the center of the egg, the yolk provides nutrients to the developing embryo, and the albumen provides additional nutrients and water.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2003>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structures that are common to both plant and animal cells are labelled </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV and I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Animal cells and plant cells have features in common such as a nucleus, cytoplasm, cell membrane, mitochondria and ribosomes. Plant and algal cells also have a cell wall, and often have chloroplasts and a permanent vacuole.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2003>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Food is stored in the structure labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure labelle IV is the pyrenoid. Pyrenoid are dense storage structures present in the chloroplast of green algae, They store starch.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2003>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One distinctive feature in the life history of liverworts is that they exhibit</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alternation of generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetative reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">asexual reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sexual reproduction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Liverworts exhibit alternation of generations. This is a type of life cycle found in plants and algae, where they alternate between two generations: a sexual phase or generation (the gametophyte) and an asexual phase or generation (the sporophyte). Vegetative, asexual, and sexual reproduction are all methods of reproduction, but they are not distinctive features of liverworts.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2003>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.   <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> A noticeable adaptation of the animal to its aquatic habitat is the possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a wide mouth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large eyes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">webbed digits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">four limbs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the possession of webbed digits, used to aid movement in water.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2003>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.   <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> The processes of water loss and intake indicated by the arrows labelled I and II are respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exhalation and osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urination and diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">osmosis and diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation and osmosis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Frogs lose water through the skin by evaporation and they absorb water by osmosis.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2003>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The umbrella-shaped fruiting body of a fully developed mushroom is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pileus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mycelium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">basidium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stipe</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The umbrella-shaped fruiting body of a fully developed mushroom is the pileus. The pileus is the technical term for the cap, or top, of a mushroom. The mycelium is the vegetative part of a fungus, consisting of a network of fine white filaments. The basidium is the microscopic, spore-producing structure found on the underside of the mushroom cap, and the stipe is the stalk that supports the cap.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>2003>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The similarity among organisms belonging to the same group will be least within each </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">family   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">order </div>", "<div style=\"font-family:Cambria;font-size:17px;\">kingdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">species</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The similarity among organisms belonging to the same group will be least within each kingdom. The reason is that a kingdom is the highest and broadest classification level in the biological taxonomy hierarchy. It includes a vast variety of organisms that share only a few similarities. For example, the animal kingdom includes organisms as diverse as sponges, worms, insects, fish, and mammals.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2003>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hermaphroditic reproduction can be found among the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">arthropods and nematodes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pisces and amphibians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">annelids and molluscs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coelenterates and platyhelminthes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hermaphroditic reproduction, where an individual organism possesses both male and female reproductive organs, can be found among the annelids and molluscs. Annelids, like earthworms, and many molluscs, like snails, are known to be hermaphrodites.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2003>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An insect whose economic importance is both harmful and beneficial is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tsetse fly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blackfly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mosquito </div>", "<div style=\"font-family:Cambria;font-size:17px;\">butterfly</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The insect whose economic importance is both harmful and beneficial is: <br/> Tsetsefly <br/>  <br/> Tsetse flies are known for transmitting diseases such as sleeping sickness in humans and nagana in livestock, which are harmful. However, they also play a role in pollination and nutrient cycling in certain ecosystems, which can be beneficial. <br/>  <br/> Note: <br/> Why the other options are not the most appropriate: <br/> Blackfly: Blackflies can be harmful as they are vectors of diseases such as river blindness (onchocerciasis) in humans and livestock. They are generally not considered beneficial in economic terms. <br/> Mosquito: Mosquitoes are primarily seen as harmful due to their role as vectors of diseases like malaria, dengue fever, and Zika virus. While they are also prey for some species and play a role in aquatic ecosystems, their negative impacts on human health outweigh their benefits. <br/> Butterfly: Butterflies, as mentioned earlier, are primarily beneficial due to their role in pollination and ecosystem health. They do not cause significant economic harm compared to their ecological benefits. <br/>  <br/> Therefore, while all these insects may have dual roles in ecosystems (beneficial and harmful), the tsetsefly is specifically noted for its significant dual economic impact-both as a disease vector and as a pollinator in certain ecosystems.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2003>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cell component that is present in a prokaryotic cell is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chloroplast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ribosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mitochondrion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nuclear envelope</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prokaryotic cells, such as bacteria, do not have a nucleus or other membrane-bound organelles. Instead, the genetic material in prokaryotic cells is contained in a central region of the cell called the nucleoid. However, they do contain ribosomes, which are not bound by a membrane. Ribosomes are responsible for protein synthesis in all cells, including prokaryotic cells.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2003>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stunted growth of a leguminous plant suffering from nitrogen deficiency may be corrected by inoculating the soil with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">denitrifying bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytic bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rhizobium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrosomonas</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rhizobium is a type of bacteria that forms symbiotic relationships with leguminous plants. These bacteria are able to fix atmospheric nitrogen into a form that the plant can use for growth. When a leguminous plant is suffering from nitrogen deficiency, inoculating the soil with Rhizobium can help to correct the deficiency and promote the plant's growth.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2003>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If water that has been coloured red is poured  at the base of a wilting plant, it will appear  as a red stain in the cell of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">epidermis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parenchyma</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The xylem is a type of tissue in plants that transports water and dissolved nutrients from the roots to the rest of the plant. It is part of the plant's vascular system. If water that has been coloured red is poured at the base of a wilting plant, it will be absorbed by the roots and transported up through the xylem to the rest of the plant. Therefore, it will appear as a red stain in the cells of the xylem.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2003>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> ' <br/>  <br/> The aim of the experiment is to demonstrate</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">that in mammals gaseous exchange takes place in the lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the part played by the pleural cavity and diaphragm in respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that a large amount of oxygen is absorbed by the lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the presence of carbon(IV)oxide in exhaled air</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is to show that in mammals gaseous exchange takes place in the lungs.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2003>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> ' <br/> In the experimental set-up, the rubber sheet represents the organ called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pleural cavity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diaphragm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intercostals muscle</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diaphragm. is a dome shaped organ that separates the thoracic cavity from the abdominal cavity.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2003>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dark reaction of photosynthesis involves the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduction of carbon (IV) oxide to organic compounds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">release of oxygen and the splitting of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photolysis of water and the production of starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">splitting of water into hydrogen ions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dark reaction of photosynthesis, also known as the Calvin cycle, involves the reduction of carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) to produce organic compounds, specifically glucose. This process does not directly depend on light, but relies on the ATP and NADPH synthesized during the light-dependent reactions of photosynthesis.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2003>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The experiment is used to demonstrate that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plants lose water through guttation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transpiration occurs through the leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water is necessary for photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leaves are important to photosynthesis</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transpiration is defined as the removal of excess water from plants to the atmosphere in the form of water vapour. The first jar has not water drops at the underside. This is because there is are no leaves. Hence, no transpiration. But the second jar has water drops on the underside. This is because of the presence of leaves which are responsible transpiration.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2003>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> In the experiment, the layer of oil serves to prevent water loss by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guttation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the experiment, the layer of oil serves to prevent water loss by evaporation</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2003>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A flower that has both stamens and pistil is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Staminate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pistillate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imperfect</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A flower that has both stamens (male reproductive organ) and pistils (female reproductive organ) is said to be perfect. Staminate refers to a flower that only has stamens, while pistillate refers to a flower that only has pistils. Imperfect flowers are those that have either stamens or pistils, but not both.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2003>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the mammalian digestive system where absorption of nutrients takes place is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ileum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oesophagus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">duodenum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ileum is the final part of the small intestine in mammals, and it is where most of the absorption of nutrients takes place. The colon is involved in the absorption of water and electrolytes, the oesophagus is a muscular tube that delivers food to the stomach, and the duodenum is the first part of the small intestine where the breakdown of food continues after it leaves the stomach.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2003>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best method of propagating sugarcane is by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seed sowing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">layering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grafting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stem cuttings</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sugarcane is typically propagated by stem cuttings. This is because sugarcane seeds are not always viable or true to type. Stem cuttings, on the other hand, are pieces of the sugarcane stalk that are planted in the ground to grow a new plant. This method ensures that the new plant will have the same characteristics as the parent plant.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2003>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In mammalian males, the excretory and reproductive systems share the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ureter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vas deferens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urethra </div>", "<div style=\"font-family:Cambria;font-size:17px;\">testes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In mammalian males, the excretory and reproductive systems share the urethra. The urethra is a tube that carries urine from the bladder to the outside of the body, and in males, it also carries semen. The ureter and vas deferens are parts of the excretory and reproductive systems respectively, but they do not serve a shared function. The testes are solely part of the reproductive system.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2003>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Metabolic production of urea is carried out in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">urinary bladder and kidney</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kidney and malpighian tubule</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The metabolic production of urea is carried out in the liver. Urea is a waste product that is produced when the liver breaks down proteins or amino acids, and ammonia. The kidneys then filter the urea from the blood and excrete it in urine. The urinary bladder, pancreas, and malpighian tubule do not produce urea.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2003>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure can be found in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sympathetic and parasympathetic nervous systems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peripheral and central nervous systems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peripheral nervous system only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">central nervous system only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">nerve cells are found in the brain , spinal cord or nerve fibres </div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2003>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> The point marked I is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">myelin sheath</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dendrites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">axon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">node of Ranvier</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Node of ranvier is a constriction by interval which interrupts the myelin sheat</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2003>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Homologous pairs of chromosomes separate during</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cytolysis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cleavage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mitosis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">meiosis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Homologous pairs of chromosomes separate during meiosis. This is a process of cell division that results in four daughter cells each with half the number of chromosomes of the parent cell. This process is fundamental to sexual reproduction and leads to genetic diversity.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2003>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a caryopsis is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">guava </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maize grain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coconut </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tomato</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A caryopsis is a type of simple dry fruit—one that is monocarpellate (formed from a single carpel) and indehiscent (not opening at maturity) and resembles a seed, or grain. The best example of a caryopsis is the maize grain.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2003>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The response of plants to external stimuli in a non-directional manner is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tactic movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phototropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geotropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nastic movement</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The response of plants to external stimuli in a non-directional manner is known as nastic movement. This type of plant movement is not dependent on the direction of the stimulus. Instead, it depends on the structural orientation of the plant part.</div>", "topic": "SUPPORT AND MOVEMENT : TROPIC TACTIC NASTIC AND SLEEP MOVEMENTS IN PLANTS"}, {"id": "objective>Biology>2003>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important enzyme that induces the ripening of fruit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethylene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indole acetic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gibberellin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cytokinin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ripening of fruits is primarily induced by the plant hormone ethylene. Ethylene is a gaseous plant hormone which regulates a wide range of biological processes in plants. It is involved in processes such as fruit ripening, flower wilting, and leaf fall. Therefore, the correct answer is ethylene.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2003>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A density-dependent factor that regulates the population size of organisms is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sudden flood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drought </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fire outbreak</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Density-dependent factors are factors whose effects on the size or growth of the population vary with the population density. These are usually biological factors such as diseases, competition, and predation. In this case, disease is a density-dependent factor because its effect on the population increases as the population density increases. Therefore, the correct answer is disease.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2003>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One example of fossil is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limestone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">firewood</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fossils are the preserved remains or traces of animals, plants, and other organisms from the past. Coal is an example of a fossil fuel, which is formed from the remains of plants that lived and died millions of years ago. Therefore, the correct answer is coal.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2003>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most effective method of dealing with non-biodegradable pollutants is by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dumping </div>", "<div style=\"font-family:Cambria;font-size:17px;\">recycling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incineration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">burying</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Non-biodegradable pollutants are substances that do not decompose naturally in the environment. The most effective method of dealing with them is by recycling. Recycling involves the process of converting waste materials into new materials and objects. This helps to reduce the consumption of raw materials, energy usage, air pollution and water pollution.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2003>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence of biomes from northern to southern Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Guinea savanna → sudan savanna → tropical rain forest → sahel savanna → estuarine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Estuarine → tropical rain forest → guinea savanna → sahel savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sahel savanna → tropical rain forest → estuarine → guinea savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sahel savanna → sudan savanna → guinea savanna → tropical rain forest → estuarine</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence of biomes from northern to southern Nigeria is Sahel savanna → sudan savanna → guinea savanna → tropical rain forest → estuarine. The Sahel savanna is the most northern biome, characterized by sparse grassland and desert-like conditions. Moving south, the Sudan savanna has more vegetation and rainfall. Further south is the Guinea savanna, which has even more vegetation and rainfall. The tropical rain forest is located in the southern part of the country and is characterized by high rainfall and a wide variety of plant and animal species. The estuarine biome is located in the coastal areas and is characterized by brackish water with a high level of salinity.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : GUINEA SAVANNA~~LOCAL(NIGERIAN) BIOMES : SUDAN SAVANNA~~LOCAL(NIGERIAN) BIOMES : TROPICAL RAINFOREST"}, {"id": "objective>Biology>2003>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mycorrhiza is an association between fungi and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protozoans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">roots of higher plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filamentous algae</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mycorrhiza is an association between fungi and roots of higher plants. The fungi help the plant absorb water and nutrients from the soil, while the plant provides the fungi with sugars and other organic substances. This is a symbiotic relationship, meaning both organisms benefit from the association.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2003>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A limiting factor in a plant population near a chemical factory is likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pH</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A limiting factor in a plant population near a chemical factory is likely to be pH. This is because chemical factories often release pollutants that can alter the pH of the surrounding soil and water, making it either too acidic or too alkaline for plants to thrive. The pH level affects the availability of nutrients in the soil, and if it's too high or too low, it can limit plant growth.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2003>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil fertility can best be conserved and renewed by the activities of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">earthworms </div>", "<div style=\"font-family:Cambria;font-size:17px;\">man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rodents </div>", "<div style=\"font-family:Cambria;font-size:17px;\">microbes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil fertility can best be conserved and renewed by the activities of microbes. Microbes play a crucial role in maintaining soil fertility by breaking down organic matter and recycling nutrients. This process, known as decomposition, releases nutrients back into the soil that plants can use to grow. Earthworms, man, and rodents also contribute to soil fertility, but microbes play the most significant role.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>2003>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pioneer organisms in ecological succession are usually the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mosses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lichens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ferns </div>", "<div style=\"font-family:Cambria;font-size:17px;\">algae</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pioneer organisms in ecological succession are usually the lichens. Lichens are often the first organisms to colonize bare rock or other harsh environments. They are able to survive in these conditions because they are a symbiotic partnership of a fungus and an alga or cyanobacterium. The fungus provides a protective structure, while the alga or cyanobacterium photosynthesizes to produce food. Over time, lichens break down the rock into soil, allowing other organisms like mosses, ferns, and algae to move in.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>2003>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a DNA strand has a base sequence TCA, its complementary strand must be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ATG </div>", "<div style=\"font-family:Cambria;font-size:17px;\">TAG </div>", "<div style=\"font-family:Cambria;font-size:17px;\">GAT</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AGT</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A DNA sequence contains only the letters A, C, G and T. (Each letter represents a small molecule, and a DNA sequence is a <strong>macromolecular</strong> chain of them.) Each letter in a DNA sequence is called a base, basepair, or nucleotide. Normally, DNA occurs as a double strand where each A is paired with a T and vice versa, and each C is paired with a G and vice versa. The reverse complement of a DNA sequence is formed by reversing the letters, interchanging A and T and interchanging C and G. Thus the reverse complement of ACCTGAG is CTCAGGT.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2003>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man and his wife are both heterozygous for the sickle-cell trait. The likely percentage of their offspring that will be either carriers or 'sicklers' is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">75%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a Punnett square for two parents who are both heterozygous for the sickle-cell trait (Ss), 25% of the offspring will be homozygous normal (SS), 50% will be heterozygous (Ss) and therefore carriers, and 25% will be homozygous for the sickle-cell trait (ss) and therefore 'sicklers'. Therefore, 75% (50% carriers + 25% 'sicklers') of their offspring will be either carriers or 'sicklers'. Option 1 is correct.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2003>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the pairs of alleles for baldness is given as Bb, a female carrier will be donated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span>Y </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">B</span>X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">B</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">B</span>Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">B</span>X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In genetics, the notation X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">B</span>X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span> represents a female who is a carrier for a trait that is X-linked, such as baldness. The capital B represents the dominant allele (not bald), and the lowercase b represents the recessive allele (bald). Because females have two X chromosomes, they can be carriers for X-linked traits without expressing them. Option 4 is correct.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>2003>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organism that has been extensively used to test the chromosome theory of heredity is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-style:italic;\"> Drosophila melanogaster </span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Musca domestica</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zea mays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Homo sapiens</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The chromosome theory of heredity was extensively tested using <span style=\"font-style:italic;\"> Drosophila melanogaster </span>, commonly known as the fruit fly. This is because fruit flies have a short life cycle, allowing for quick generation turnover, and they have large numbers of offspring, which provides a large sample size for genetic studies.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2003>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A feature associated with the Y-chromosome in humans is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">long eyelashes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prominent fingernails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facial hairs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enlarged breast</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Y-chromosome are used prevent the formation of breasts, and cause growth of facial hair, change in voice, and other characteristics typical of boys and men. </div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>2003>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of reproduction that lead to variation in animal and plant population is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">budding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sexual</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetative   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">asexual</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sexual reproduction leads to variation in animal and plant populations. This is because it involves the combination of genetic material from two parents, resulting in offspring that are genetically different from both parents. This genetic diversity is a key driver of evolution and adaptation.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2003>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An insect with a mandibulate mouthpart will obtain its food by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">biting and chewing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chewing and sucking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chewing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sucking</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insects with mandibulate mouthparts, such as beetles and ants, obtain their food by biting and chewing. Mandibulate mouthparts are designed for grinding and chewing food, not for sucking.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTIONS IN ORGANISMS"}, {"id": "objective>Biology>2003>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An argument against Lamarck's theory of evolution is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disuse of body part cannot weaken the part </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disused part is dropped off in the offspring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acquired traits cannot be passed onto the offspring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">traits cannot be acquired through constant use of body parts</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lamarck's theory of evolution, also known as Lamarckism, proposed that an organism can change during its lifetime in response to its environment, and those changes are passed on to its offspring. However, this theory is largely discredited today because acquired traits (changes an organism undergoes in its lifetime due to environmental factors) cannot be passed onto the offspring. This is because changes in an organism's physical characteristics do not change the genes that it passes on to its offspring.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2003>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of sunken stomata and the folding of leaves are adaptations to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent entry of pathogens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce water loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove excess water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent guttation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sunken stomata and the folding of leaves are adaptations to reduce water loss. Sunken stomata are a common adaptation of plants in arid environments. They are located below the leaf surface, which helps to reduce water loss by transpiration. Similarly, the folding of leaves reduces the surface area exposed to the sun and wind, thereby reducing water loss.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2003>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Spines and shells on animals are adaptations for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">camouflage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemical defence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">physical defence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mimicry</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spines and shells on animals are adaptations for physical defence. They serve as protective structures that deter predators. Camouflage, chemical defence, and mimicry are other forms of adaptations, but they do not directly relate to the presence of spines and shells.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2003>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of cryptic colouration is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mottled colours on moths that rest on lichen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bright colour of an insect pollinated flower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">green colour of a plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bright marks on a poisonous tropical frog on variegated leaves</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cryptic colouration refers to the use of coloration or patterns as a means of camouflage. The mottled colours on moths that rest on lichen is an example of this, as the moth's coloration allows it to blend in with its surroundings and avoid detection by predators.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2003>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following requires the use of carbon dating to prove that evolution has occurred?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Comparative anatomy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biochemical similarities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Molecular records</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fossil records</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon dating is a method used to determine the age of ancient artifacts and fossils. It is used in the fossil records to prove that evolution has occurred by showing that certain species existed in the past but do not exist today, or that certain species have evolved over time. Comparative anatomy, biochemical similarities, and molecular records are other ways to prove evolution, but they do not require the use of carbon dating.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2003>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The inactive state exhibited by an animal during hot dry season is termed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aestivation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dormancy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hibernation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aestivation is the state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions. It takes place during times of heat and dryness, the hot dry season, which are conditions that are the opposite of those that trigger hibernation.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}];
